const BRAND_ICON_SIZES = { small: 20, medium: 32, large: 48 };

export const BrandIcon = forwardRef(function BrandIcon(
  { name, size = 'medium', className, style, ...props },
  ref
) {
  const iconInfo = brandIconData[name];
  if (!iconInfo) { console.warn(`BrandIcon "${name}" not found`); return null; }
  const dimension = typeof size === 'number' ? size : BRAND_ICON_SIZES[size] || BRAND_ICON_SIZES.medium;
  const { viewBox, content } = iconInfo;
  return (
    <svg
      ref={ref}
      width={dimension}
      height={dimension}
      viewBox={viewBox}
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      className={className}
      style={{ display: 'inline-block', verticalAlign: 'middle', ...style }}
      aria-hidden="true"
      dangerouslySetInnerHTML={{ __html: content }}
      {...props}
    />
  );
});

export const brandIconNames = Object.keys(brandIconData);
export const getBrandIconNames = () => brandIconNames;
